import React, { Component } from "react";

class Tools extends Component {
  toolsList = [
    {
      id: 1,
      frontEnd: ["JavaScript", "Angular", "ReactJS", "SASS", "HTML5"],
      backEnd: ["PHP", "MySQL", "ExpressJS"],
      tools: [
        "npm",
        "Git",
        "Bitbucket",
        "Jira",
        "Confluence",
        "NodeJS",
        "APIs",
        "Docker",
        "MongoDB",
        "Adobe CC",
        "FIgma",
      ],
    },
  ];
  render() {
    return (
      <div className="about-container">
        <div className="row">
          <div className="col-md-4">
            {this.toolsList.map(({ frontEnd }, i) => (
              <div>
                <h4 key={i}>Front End</h4>
                {frontEnd.map((x, j) => (
                  <span style={{ marginRight: 10 }} key={j}>
                    {x}{" "}
                  </span>
                ))}
              </div>
            ))}
          </div>
          <div className="col-md-4">
            {this.toolsList.map(({ backEnd }, i) => (
              <div>
                <h4 key={i}>Back End</h4>
                <ul>
                  {backEnd.map((x, j) => (
                    <li key={j}>{x} </li>
                  ))}
                </ul>
              </div>
            ))}
          </div>
          <div className="col-md-4">
            {this.toolsList.map(({ tools }, i) => (
              <div>
                <h4 key={i}>Tools</h4>
                {tools.map((x, j) => (
                  <span style={{ marginRight: 10 }} key={j}>
                    {x}{" "}
                  </span>
                ))}
              </div>
            ))}
          </div>
        </div>
      </div>
    );
  }
}

export default Tools;
